// Metals API Service using Alpha Vantage (free tier)
// You'll need to get an API key from https://www.alphavantage.co/

const API_KEY = process.env.REACT_APP_ALPHA_VANTAGE_API_KEY || 'demo';
const BASE_URL = 'https://www.alphavantage.co/query';

export interface MetalPrice {
  symbol: string;
  price: number;
  change: number;
  changePercent: number;
  lastUpdated: string;
}

export interface MetalsData {
  gold: MetalPrice;
  silver: MetalPrice;
  timestamp: number;
}

// Fallback mock data in case API fails or for development
export const mockMetalsData: MetalsData = {
  gold: {
    symbol: 'XAU/USD',
    price: 2150.75,
    change: 52.25,
    changePercent: 2.49,
    lastUpdated: new Date().toISOString()
  },
  silver: {
    symbol: 'XAG/USD',
    price: 25.80,
    change: 0.31,
    changePercent: 1.22,
    lastUpdated: new Date().toISOString()
  },
  timestamp: Date.now()
};

export const fetchLiveMetalsPrices = async (): Promise<MetalsData> => {
  try {
    // Alpha Vantage endpoint for gold and silver
    const goldUrl = `${BASE_URL}?function=GLOBAL_QUOTE&symbol=GC=F&apikey=${API_KEY}`;
    const silverUrl = `${BASE_URL}?function=GLOBAL_QUOTE&symbol=SI=F&apikey=${API_KEY}`;

    const [goldResponse, silverResponse] = await Promise.all([
      fetch(goldUrl),
      fetch(silverUrl)
    ]);

    if (!goldResponse.ok || !silverResponse.ok) {
      throw new Error('Failed to fetch metals data');
    }

    const goldData = await goldResponse.json();
    const silverData = await silverResponse.json();

    // Extract prices from Alpha Vantage response
    const goldPrice = parseFloat(goldData['Global Quote']['05. price']);
    const goldChange = parseFloat(goldData['Global Quote']['09. change']);
    const goldChangePercent = parseFloat(goldData['Global Quote']['10. change percent'].replace('%', ''));

    const silverPrice = parseFloat(silverData['Global Quote']['05. price']);
    const silverChange = parseFloat(silverData['Global Quote']['09. change']);
    const silverChangePercent = parseFloat(silverData['Global Quote']['10. change percent'].replace('%', ''));

    return {
      gold: {
        symbol: 'GC=F',
        price: goldPrice,
        change: goldChange,
        changePercent: goldChangePercent,
        lastUpdated: new Date().toISOString()
      },
      silver: {
        symbol: 'SI=F',
        price: silverPrice,
        change: silverChange,
        changePercent: silverChangePercent,
        lastUpdated: new Date().toISOString()
      },
      timestamp: Date.now()
    };

  } catch (error) {
    console.error('Error fetching metals prices:', error);

    // Return mock data with slight random variations for demo
    const mockData = { ...mockMetalsData };
    mockData.gold.price += (Math.random() - 0.5) * 10;
    mockData.gold.change = mockData.gold.price - 2150.75;
    mockData.silver.price += (Math.random() - 0.5) * 0.5;
    mockData.silver.change = mockData.silver.price - 25.80;
    mockData.timestamp = Date.now();

    return mockData;
  }
};

export const subscribeToMetalsUpdates = (
  callback: (data: MetalsData) => void,
  interval: number = 30000 // 30 seconds
): (() => void) => {
  let isSubscribed = true;

  const fetchAndUpdate = async () => {
    if (!isSubscribed) return;

    try {
      const data = await fetchLiveMetalsPrices();
      if (isSubscribed) {
        callback(data);
      }
    } catch (error) {
      console.error('Error in metals subscription:', error);
    }
  };

  // Initial fetch
  fetchAndUpdate();

  // Set up interval
  const intervalId = setInterval(fetchAndUpdate, interval);

  // Cleanup function
  return () => {
    isSubscribed = false;
    clearInterval(intervalId);
  };
};
